import{execSync}from"node:child_process";import os from"node:os";import path from"node:path";import semver from"semver";import{getJSON}from"../httpUtil.js";import{BrowserPlatform,ChromeReleaseChannel}from"./types.js";function folder(e){switch(e){case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return"linux64";case BrowserPlatform.MAC_ARM:return"mac-arm64";case BrowserPlatform.MAC:return"mac-x64";case BrowserPlatform.WIN32:return"win32";case BrowserPlatform.WIN64:return"win64"}}export function resolveDownloadUrl(e,o,r="https://storage.googleapis.com/chrome-for-testing-public"){return`${r}/${resolveDownloadPath(e,o).join("/")}`}export function resolveDownloadPath(e,o){return[o,folder(e),`chrome-${folder(e)}.zip`]}export function relativeExecutablePath(e,o){switch(e){case BrowserPlatform.MAC:case BrowserPlatform.MAC_ARM:return path.join("chrome-"+folder(e),"Google Chrome for Testing.app","Contents","MacOS","Google Chrome for Testing");case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return path.join("chrome-linux64","chrome");case BrowserPlatform.WIN32:case BrowserPlatform.WIN64:return path.join("chrome-"+folder(e),"chrome.exe")}}let baseVersionUrl="https://googlechromelabs.github.io/chrome-for-testing";export function changeBaseVersionUrlForTesting(e){baseVersionUrl=e}export function resetBaseVersionUrlForTesting(){baseVersionUrl="https://googlechromelabs.github.io/chrome-for-testing"}export async function getLastKnownGoodReleaseForChannel(e){const o=await getJSON(new URL(`${baseVersionUrl}/last-known-good-versions.json`));for(const e of Object.keys(o.channels))o.channels[e.toLowerCase()]=o.channels[e],delete o.channels[e];return o.channels[e]}export async function getLastKnownGoodReleaseForMilestone(e){return(await getJSON(new URL(`${baseVersionUrl}/latest-versions-per-milestone.json`))).milestones[e]}export async function getLastKnownGoodReleaseForBuild(e){return(await getJSON(new URL(`${baseVersionUrl}/latest-patch-versions-per-build.json`))).builds[e]}export async function resolveBuildId(e){return Object.values(ChromeReleaseChannel).includes(e)?(await getLastKnownGoodReleaseForChannel(e)).version:e.match(/^\d+$/)?(await getLastKnownGoodReleaseForMilestone(e))?.version:e.match(/^\d+\.\d+\.\d+$/)?(await getLastKnownGoodReleaseForBuild(e))?.version:void 0}const WINDOWS_ENV_PARAM_NAMES=["PROGRAMFILES","ProgramW6432","ProgramFiles(x86)","LOCALAPPDATA"];function getChromeWindowsLocation(e,o){if(0===o.size)throw new Error("Non of the common Windows Env variables were set");let r;switch(e){case ChromeReleaseChannel.STABLE:r="Google\\Chrome\\Application\\chrome.exe";break;case ChromeReleaseChannel.BETA:r="Google\\Chrome Beta\\Application\\chrome.exe";break;case ChromeReleaseChannel.CANARY:r="Google\\Chrome SxS\\Application\\chrome.exe";break;case ChromeReleaseChannel.DEV:r="Google\\Chrome Dev\\Application\\chrome.exe"}return[...o.values()].map(e=>path.win32.join(e,r))}function getWslVariable(e){try{const o=execSync(`cmd.exe /c echo %${e.toLocaleUpperCase()}%`,{stdio:["ignore","pipe","ignore"],encoding:"utf-8"}).trim();if(o)return o}catch{}}function getWslLocation(e){if(!execSync("wslinfo --version",{stdio:["ignore","pipe","ignore"],encoding:"utf-8"}).trim())throw new Error("Not in WSL or unsupported version of WSL.");const o=new Set;for(const e of WINDOWS_ENV_PARAM_NAMES){const r=getWslVariable(e);r&&o.add(r)}return getChromeWindowsLocation(e,o).map(e=>execSync(`wslpath "${e}"`).toString().trim())}function getChromeLinuxOrWslLocation(e){const o=[];switch(e){case ChromeReleaseChannel.STABLE:o.push("/opt/google/chrome/chrome");break;case ChromeReleaseChannel.BETA:o.push("/opt/google/chrome-beta/chrome");break;case ChromeReleaseChannel.CANARY:o.push("/opt/google/chrome-canary/chrome");break;case ChromeReleaseChannel.DEV:o.push("/opt/google/chrome-unstable/chrome")}try{const r=getWslLocation(e);r&&o.push(...r)}catch{}return o}export function resolveSystemExecutablePaths(e,o){switch(e){case BrowserPlatform.WIN64:case BrowserPlatform.WIN32:const e=new Set(WINDOWS_ENV_PARAM_NAMES.map(e=>process.env[e]).filter(e=>!!e));return e.add("C:\\Program Files"),e.add("C:\\Program Files (x86)"),e.add("D:\\Program Files"),e.add("D:\\Program Files (x86)"),getChromeWindowsLocation(o,e);case BrowserPlatform.MAC_ARM:case BrowserPlatform.MAC:switch(o){case ChromeReleaseChannel.STABLE:return["/Applications/Google Chrome.app/Contents/MacOS/Google Chrome"];case ChromeReleaseChannel.BETA:return["/Applications/Google Chrome Beta.app/Contents/MacOS/Google Chrome Beta"];case ChromeReleaseChannel.CANARY:return["/Applications/Google Chrome Canary.app/Contents/MacOS/Google Chrome Canary"];case ChromeReleaseChannel.DEV:return["/Applications/Google Chrome Dev.app/Contents/MacOS/Google Chrome Dev"]}case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return getChromeLinuxOrWslLocation(o)}}export function resolveDefaultUserDataDir(e,o){switch(e){case BrowserPlatform.WIN64:case BrowserPlatform.WIN32:switch(o){case ChromeReleaseChannel.STABLE:return path.join(getLocalAppDataWin(),"Google","Chrome","User Data");case ChromeReleaseChannel.BETA:return path.join(getLocalAppDataWin(),"Google","Chrome Beta","User Data");case ChromeReleaseChannel.CANARY:return path.join(getLocalAppDataWin(),"Google","Chrome SxS","User Data");case ChromeReleaseChannel.DEV:return path.join(getLocalAppDataWin(),"Google","Chrome Dev","User Data")}case BrowserPlatform.MAC_ARM:case BrowserPlatform.MAC:switch(o){case ChromeReleaseChannel.STABLE:return path.join(getBaseUserDataDirPathMac(),"Chrome");case ChromeReleaseChannel.BETA:return path.join(getBaseUserDataDirPathMac(),"Chrome Beta");case ChromeReleaseChannel.DEV:return path.join(getBaseUserDataDirPathMac(),"Chrome Dev");case ChromeReleaseChannel.CANARY:return path.join(getBaseUserDataDirPathMac(),"Chrome Canary")}case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:switch(o){case ChromeReleaseChannel.STABLE:return path.join(getConfigHomeLinux(),"google-chrome");case ChromeReleaseChannel.BETA:return path.join(getConfigHomeLinux(),"google-chrome-beta");case ChromeReleaseChannel.CANARY:return path.join(getConfigHomeLinux(),"google-chrome-canary");case ChromeReleaseChannel.DEV:return path.join(getConfigHomeLinux(),"google-chrome-unstable")}}}function getLocalAppDataWin(){return process.env.LOCALAPPDATA||path.join(os.homedir(),"AppData","Local")}function getConfigHomeLinux(){return process.env.CHROME_CONFIG_HOME||process.env.XDG_CONFIG_HOME||path.join(os.homedir(),".config")}function getBaseUserDataDirPathMac(){return path.join(os.homedir(),"Library","Application Support","Google")}export function compareVersions(e,o){if(!semver.valid(e))throw new Error(`Version ${e} is not a valid semver version`);if(!semver.valid(o))throw new Error(`Version ${o} is not a valid semver version`);return semver.gt(e,o)?1:semver.lt(e,o)?-1:0}